def hash_password(password: str) -> str:
    return hashlib.sha256(password.encode("utf-8")).hexdigest()


def verify_password(username: str, password: str) -> bool:
    user = users.get(username)
    if not user:
        return False
    return hmac.compare_digest(user["password_hash"], hash_password(password))


def login_required(fn):
    @wraps(fn)
    def wrapper(*args, **kwargs):
        if not session.get("authenticated"):
            return redirect(url_for("login"))
        return fn(*args, **kwargs)
    return wrapper


def api_auth_required(fn):
    @wraps(fn)
    def wrapper(*args, **kwargs):
        api_key = request.headers.get("X-API-Key", "")
        expected = os.environ.get("API_KEY", "change-me")
        if not hmac.compare_digest(api_key, expected):
            return jsonify({"error": "unauthorized"}), 401
        return fn(*args, **kwargs)
    return wrapper


@app.route("/", methods=["GET"])
def index():
    if session.get("authenticated"):
        return redirect(url_for("dashboard"))
    return redirect(url_for("login"))


@app.route("/login", methods=["GET", "POST"])
def login():
    error = None
    if request.method == "POST":
        username = request.form.get("username", "")
        password = request.form.get("password", "")
        user = users.get(username)

        if not user or not verify_password(username, password):
            error = "Invalid credentials"
            return render_template_string(login_page, error=error), 401

        session.clear()
        session["pending_user"] = username

        if user["mfa_enabled"]:
            session["mfa_required"] = True
            return redirect(url_for("otp"))
        else:
            session["authenticated"] = True
            session["username"] = username
            session.pop("pending_user", None)
            session.pop("mfa_required", None)
            return redirect(url_for("dashboard"))

    return render_template_string(login_page, error=error)


@app.route("/otp", methods=["GET"])
def otp():
    if not session.get("pending_user") or not session.get("mfa_required"):
        return redirect(url_for("login"))
    return render_template_string(otp_page, error=None)


@app.route("/verify-otp", methods=["POST"])
def verify_otp():
    username = session.get("pending_user")
    if not username or not session.get("mfa_required"):
        return redirect(url_for("login"))

    otp = request.form.get("otp", "")
    user = users.get(username)
    if not user or not user.get("mfa_secret"):
        return redirect(url_for("login"))

    totp = pyotp.TOTP(user["mfa_secret"])
    if not totp.verify(otp, valid_window=1):
        return render_template_string(otp_page, error="Invalid OTP"), 401

    session["authenticated"] = True
    session["username"] = username
    session.pop("pending_user", None)
    session.pop("mfa_required", None)
    return redirect(url_for("dashboard"))


@app.route("/dashboard", methods=["GET"])
@login_required
def dashboard():
    return render_template_string(dashboard_page, username=session.get("username"))


@app.route("/logout", methods=["GET"])
def logout():
    session.clear()
    return redirect(url_for("login"))


@app.route("/api/direct-login", methods=["POST"])
@api_auth_required
def api_direct_login():
    data = request.get_json(silent=True) or {}
    username = data.get("username", "")
    password = data.get("password", "")

    if not verify_password(username, password):
        return jsonify({"error": "invalid credentials"}), 401

    user = users.get(username)
    if not user:
        return jsonify({"error": "invalid credentials"}), 401

    token_payload = f"{username}:{int(time.time())}"
    token = base64.urlsafe_b64encode(
        hmac.new(app.secret_key if isinstance(app.secret_key, bytes) else str(app.secret_key).encode(), token_payload.encode(), hashlib.sha256).digest()
    ).decode()

    return jsonify({
        "status": "ok",
        "username": username,
        "authenticated": True,
        "mfa_skipped": True,
        "token": token
    })


@app.route("/api/login", methods=["POST"])
def api_login():
    data = request.get_json(silent=True) or {}
    username = data.get("username", "")
    password = data.get("password", "")

    if not verify_password(username, password):
        return jsonify({"error": "invalid credentials"}), 401

    user = users.get(username)
    if user and user["mfa_enabled"]:
        return jsonify({"mfa_required": True, "message": "OTP required"}), 200

    return jsonify({"authenticated": True, "username": username}), 200


@app.route("/api/verify-otp", methods=["POST"])
def api_verify_otp():
    data = request.get_json(silent=True) or {}
    username = data.get("username", "")
    otp = data.get("otp", "")

    user = users.get(username)
    if not user or not user.get("mfa_enabled") or not user.get("mfa_secret"):
        return jsonify({"error": "mfa not enabled"}), 400

    totp = pyotp.TOTP(user["mfa_secret"])
    if not totp.verify(otp, valid_window=1):
        return jsonify({"error": "invalid otp"}), 401

    return jsonify({"authenticated": True, "username": username}), 200


